diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 706cb828acc6..751a9f71da16 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -4149,9 +4149,33 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
       return BinaryOperator::CreateOr(Ov, NewCmp);
     }
   }
-
-  // (~x) | y  -->  ~(x & (~y))  iff that gets rid of inversions
-  if (sinkNotIntoOtherHandOfLogicalOp(I))
+  // Pattern: overflow | (prod > K) -> X > K/C (for umul with constant C)
+  const WithOverflowInst *MulWO;
+  const Value *MulWOV;
+  const APInt *MulC1, *MulC2;
+  ICmpInst::Predicate MulPred;
+  Value *MulOv;
+  if (match(&I, m_c_Or(m_CombineAnd(m_ExtractValue<1>(m_CombineAnd(
+                                        m_WithOverflowInst(MulWO), m_Value(MulWOV))),
+                                    m_Value(MulOv)),
+                       m_OneUse(m_ICmp(MulPred, m_ExtractValue<0>(m_Deferred(MulWOV)),
+                                       m_APInt(MulC2))))) &&
+      MulWO->getBinaryOp() == Instruction::Mul && !MulWO->isSigned() &&
+      match(MulWO->getRHS(), m_APInt(MulC1)) &&
+      (MulPred == ICmpInst::ICMP_UGT || MulPred == ICmpInst::ICMP_UGE)) {
+    // Ensure C2 is less than max value of the product type (2^N - 1).
+    unsigned BitWidth = MulWO->getType()->getStructElementType(0)->getScalarSizeInBits();
+    APInt MaxVal = APInt::getMaxValue(BitWidth);
+    if (MulC2->ult(MaxVal) && !MulC1->isZero()) {
+      APInt Quotient = MulC2->udiv(*MulC1);
+      if (MulPred == ICmpInst::ICMP_UGT) {
+        Value *NewCmp = Builder.CreateICmp(ICmpInst::ICMP_UGT, MulWO->getLHS(),
+                                           ConstantInt::get(MulWO->getLHS()->getType(), Quotient));
+        return replaceInstUsesWith(I, NewCmp);
+      }
+      // TODO: handle UGE.
+    }
+  }
     return &I;

   // Improve "get low bit mask up to and including bit X" pattern:

